import { SolidComponent } from '@/type';
import { cn } from '@/utils/cn';
import { Component } from 'solid-js';

type DiffProps = {
  images: SolidComponent[];
  class?: Partial<Record<'root' | 'item1' | 'item2' | 'resizer', string>>;
};

const Diff: Component<DiffProps> = p => {
  if (p.images.length !== 2) {
    console.warn('You need to provide exactly 2 images');
    return <></>;
  }
  return (
    <figure class={cn('diff aspect-video', p.class?.root)} tabindex="0">
      <div class={cn('diff-item-1', p.class?.item1)} role="img" tabindex="0">
        {p.images[0] as Element}
      </div>
      <div class={cn('diff-item-2', p.class?.item2)} role="img">
        {p.images[1] as Element}
      </div>
      <div class={cn('diff-resizer', p.class?.resizer)}></div>
    </figure>
  );
};

export { Diff };
